"""
MABE Bootstrap: De Novo Molecule Generator

Run: python3 bootstrap_de_novo.py

Creates:
  core/de_novo_generator.py   — Fragment-based combinatorial enumeration + scoring
  tests/test_de_novo_generator.py — 50 tests covering all generation modes

Libraries: 28 backbones x 35 arms, HSAB pre-filter, SA score,
           generate_candidates(), generate_and_screen(), generate_for_host()

Prereqs: auto_descriptor.py, unified_scorer_v2.py, design_engine_v2.py
"""
import base64, pathlib, os

FILES = {
    "core/de_novo_generator.py": "",
    "tests/test_de_novo_generator.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_de_novo_generator.py -v")
    print("  Self-test: python3 core/de_novo_generator.py")

if __name__ == "__main__":
    main()